// ChartCard.jsx — Renders a single chart using Recharts

import {
  BarChart, Bar, LineChart, Line, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, Legend,
  ResponsiveContainer, AreaChart, Area
} from "recharts";

const COLOR_PALETTES = {
  default: ["#4f8ef7", "#7c5cfc", "#00d4aa", "#f7a84f", "#f75959", "#e879f9"],
  blue:    ["#0ea5e9", "#38bdf8", "#7dd3fc", "#bae6fd", "#0284c7", "#0369a1"],
  warm:    ["#f97316", "#fb923c", "#fbbf24", "#f43f5e", "#e11d48", "#c2410c"],
  dark:    ["#a78bfa", "#34d399", "#fb7185", "#fbbf24", "#60a5fa", "#f472b6"],
};

const fmt = (val) => {
  if (typeof val !== "number") return val;
  if (val >= 1_000_000) return `${(val / 1_000_000).toFixed(1)}M`;
  if (val >= 1_000) return `${(val / 1_000).toFixed(1)}K`;
  return Number.isInteger(val) ? val : val.toFixed(2);
};

const CustomTooltip = ({ active, payload, label }) => {
  if (!active || !payload?.length) return null;
  return (
    <div style={ttStyles.box}>
      <p style={ttStyles.label}>{label}</p>
      {payload.map((p, i) => (
        <p key={i} style={{ ...ttStyles.val, color: p.color }}>
          {p.name}: <strong>{fmt(p.value)}</strong>
        </p>
      ))}
    </div>
  );
};

const ttStyles = {
  box: {
    background: "#1a1f2e", border: "1px solid #2a3040",
    borderRadius: "10px", padding: "10px 14px",
    boxShadow: "0 8px 24px rgba(0,0,0,0.4)",
  },
  label: { fontSize: "12px", color: "#8891a8", marginBottom: "6px" },
  val: { fontSize: "13px", fontWeight: 500 },
};

export default function ChartCard({ chart, colorSchema = "default", index = 0 }) {
  const colors = COLOR_PALETTES[colorSchema] || COLOR_PALETTES.default;
  const data = chart.data || [];
  const xKey = chart.x_axis;
  const yKey = chart.y_axis;

  // Find the actual y key from data
  const dataKeys = data.length > 0
    ? Object.keys(data[0]).filter((k) => k !== xKey)
    : [yKey];

  const renderChart = () => {
    switch (chart.chart_type) {
      case "line":
        return (
          <LineChart data={data}>
            <CartesianGrid strokeDasharray="3 3" stroke="#1e2333" />
            <XAxis dataKey={xKey} tick={{ fill: "#8891a8", fontSize: 11 }} axisLine={false} tickLine={false} />
            <YAxis tickFormatter={fmt} tick={{ fill: "#8891a8", fontSize: 11 }} axisLine={false} tickLine={false} />
            <Tooltip content={<CustomTooltip />} />
            <Legend wrapperStyle={{ fontSize: "12px" }} />
            {dataKeys.map((key, i) => (
              <Line key={key} type="monotone" dataKey={key} stroke={colors[i % colors.length]}
                strokeWidth={2.5} dot={{ r: 3, fill: colors[i % colors.length] }}
                activeDot={{ r: 5 }} />
            ))}
          </LineChart>
        );

      case "area":
        return (
          <AreaChart data={data}>
            <defs>
              {dataKeys.map((key, i) => (
                <linearGradient key={key} id={`grad-${i}`} x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor={colors[i % colors.length]} stopOpacity={0.3} />
                  <stop offset="95%" stopColor={colors[i % colors.length]} stopOpacity={0} />
                </linearGradient>
              ))}
            </defs>
            <CartesianGrid strokeDasharray="3 3" stroke="#1e2333" />
            <XAxis dataKey={xKey} tick={{ fill: "#8891a8", fontSize: 11 }} axisLine={false} tickLine={false} />
            <YAxis tickFormatter={fmt} tick={{ fill: "#8891a8", fontSize: 11 }} axisLine={false} tickLine={false} />
            <Tooltip content={<CustomTooltip />} />
            {dataKeys.map((key, i) => (
              <Area key={key} type="monotone" dataKey={key}
                stroke={colors[i % colors.length]} strokeWidth={2}
                fill={`url(#grad-${i})`} />
            ))}
          </AreaChart>
        );

      case "pie":
        return (
          <PieChart>
            <Pie data={data} dataKey={dataKeys[0]} nameKey={xKey}
              cx="50%" cy="50%" outerRadius={90} innerRadius={40}
              paddingAngle={3} strokeWidth={0}>
              {data.map((_, i) => (
                <Cell key={i} fill={colors[i % colors.length]} />
              ))}
            </Pie>
            <Tooltip content={<CustomTooltip />} />
            <Legend wrapperStyle={{ fontSize: "12px" }} />
          </PieChart>
        );

      default: // bar
        return (
          <BarChart data={data} barCategoryGap="30%">
            <CartesianGrid strokeDasharray="3 3" stroke="#1e2333" vertical={false} />
            <XAxis dataKey={xKey} tick={{ fill: "#8891a8", fontSize: 11 }} axisLine={false} tickLine={false} />
            <YAxis tickFormatter={fmt} tick={{ fill: "#8891a8", fontSize: 11 }} axisLine={false} tickLine={false} />
            <Tooltip content={<CustomTooltip />} />
            <Legend wrapperStyle={{ fontSize: "12px" }} />
            {dataKeys.map((key, i) => (
              <Bar key={key} dataKey={key} fill={colors[i % colors.length]}
                radius={[4, 4, 0, 0]} maxBarSize={48} />
            ))}
          </BarChart>
        );
    }
  };

  return (
    <div style={{ ...styles.card, animationDelay: `${index * 0.1}s` }} className="fade-up">
      {/* Header */}
      <div style={styles.cardHeader}>
        <div style={styles.titleRow}>
          <div style={{ ...styles.typeBadge, background: `${colors[0]}22`, color: colors[0] }}>
            {chart.chart_type}
          </div>
          <h3 style={styles.cardTitle}>{chart.title}</h3>
        </div>
      </div>

      {/* Chart */}
      <div style={styles.chartWrap}>
        <ResponsiveContainer width="100%" height={240}>
          {renderChart()}
        </ResponsiveContainer>
      </div>
    </div>
  );
}

const styles = {
  card: {
    background: "var(--bg2)",
    border: "1px solid var(--border)",
    borderRadius: "var(--radius-lg)",
    overflow: "hidden",
    transition: "border-color 0.2s",
  },
  cardHeader: {
    padding: "16px 20px 12px",
    borderBottom: "1px solid var(--border)",
  },
  titleRow: { display: "flex", alignItems: "center", gap: "10px" },
  typeBadge: {
    padding: "3px 10px",
    borderRadius: "20px",
    fontSize: "11px",
    fontWeight: 700,
    textTransform: "uppercase",
    letterSpacing: "0.05em",
  },
  cardTitle: {
    fontSize: "14px",
    fontWeight: 700,
    color: "var(--text)",
    letterSpacing: "-0.2px",
  },
  chartWrap: { padding: "16px 8px 8px" },
};
